const body = $input.first().json.body || $input.first().json;
const prompt = body.prompt || '';

const durationMatch = prompt.match(/(\d+)\s*(?:jours?|days?|nuits?|nights?|semaines?|weeks?)/i);
const duration = durationMatch ? parseInt(durationMatch[1]) : 7;

let destination = prompt
  .replace(/guide/gi, '')
  .replace(/\d+\s*(?:jours?|days?|nuits?|nights?|semaines?|weeks?)/gi, '')
  .replace(/[\s]*[àa][\s]*/gi, ' ')
  .replace(/complet|premium|voyage|trip|travel/gi, '')
  .trim()
  .replace(/\s+/g, ' ');

const slug = destination
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, '')
  .trim()
  .replace(/\s+/g, '-');

let price = 14.90;
if (duration >= 10) price = 24.90;
else if (duration >= 7) price = 19.90;
else if (duration >= 5) price = 16.90;

return [{
  json: {
    original_prompt: prompt,
    destination: destination.trim() || 'Destination',
    duration: duration,
    slug: slug || 'guide-voyage',
    price: price,
    price_formatted: price.toFixed(2).replace('.', ',') + '€',
    price_cents: Math.round(price * 100),
    email: body.email || null,
    created_at: new Date().toISOString(),
    guide_id: 'guide_' + Date.now()
  }
}];

